title: $:/plugins/realaaa/subscription-tracker/modules/daysuntil.js
type: application/javascript
module-type: filteroperator

Filter operator: for each input title interpreted as a TiddlyWiki date string
(YYYYMMDDhhmmsssss), returns the integer number of UTC days from today until
that date. Negative for past dates. Skips unparseable inputs.

Why a JS module: TW 5.4 core does not provide a date-math primitive that
returns days-between-dates. The auto-roll renewal-date feature (spec §5.3,
§7.6) and the renewal-soon highlighting both need this. Keeping the
implementation in-plugin (rather than depending on a third-party plugin)
preserves the dependency-free goal.

\*/
"use strict";

exports.daysuntil = function(source, operator, options) {
    var results = [];
    var now = new Date();
    var nowUtc = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate());
    var msPerDay = 24 * 60 * 60 * 1000;
    source(function(tiddler, title) {
        var d = $tw.utils.parseDate(title);
        if (d && $tw.utils.isDate(d) && d.toString() !== "Invalid Date") {
            var thenUtc = Date.UTC(d.getUTCFullYear(), d.getUTCMonth(), d.getUTCDate());
            results.push(String(Math.round((thenUtc - nowUtc) / msPerDay)));
        }
    });
    return results;
};
","type":"application/javascript","module-type":"filteroperator"},"$:/plugins/realaaa/subscription-tracker/modules/nextrenewal.js":{"title":"$:/plugins/realaaa/subscription-tracker/modules/nextrenewal.js","text":"/*\
title: $:/plugins/realaaa/subscription-tracker/modules/nextrenewal.js
type: application/javascript
module-type: filteroperator

Filter operator: takes an input date string and a period (in days) as operand.
Returns the next future occurrence of the date — i.e. if the input is already
in the future, returns it unchanged; if it's in the past, adds period-day
chunks until the result is in the future.

Used by sub.next-renewal to compute auto-rolled renewal dates without
requiring the user to manually update the field.

Why a JS module: TW 5.4 vanilla has no filter operator that adds N days
to a date string. The `days` operator selects tiddlers by date, not date
arithmetic. Self-contained in this plugin — no external deps.

\*/
"use strict";

exports.nextrenewal = function(source, operator, options) {
    var results = [];
    var now = new Date();
    var msPerDay = 24 * 60 * 60 * 1000;
    var periodDays = parseFloat(operator.operand);
    if (!isFinite(periodDays) || periodDays <= 0) {
        return results;
    }
    source(function(tiddler, title) {
        var d = $tw.utils.parseDate(title);
        if (!d || !$tw.utils.isDate(d) || d.toString() === "Invalid Date") return;
        if (d.getTime() >= now.getTime()) {
            results.push(title);
            return;
        }
        var daysSince = (now.getTime() - d.getTime()) / msPerDay;
        var periodsToAdd = Math.ceil(daysSince / periodDays);
        var newDate = new Date(d.getTime() + periodsToAdd * periodDays * msPerDay);
        results.push($tw.utils.stringifyDate(newDate));
    });
    return results;
};
","type":"application/javascript","module-type":"filteroperator"},"$:/plugins/realaaa/subscription-tracker/readme":{"title":"$:/plugins/realaaa/subscription-tracker/readme","text":"! Subscription Tracker

A vanilla TiddlyWiki 5.4+ plugin that turns ''subscriptions''-tagged tiddlers into a Notion-style table with:

* multi-currency monthly + yearly totals (single configurable display currency)
* trial tracking with countdown
* render-time auto-rolled renewal dates (no field churn)
* structured editor for adding/editing subscriptions
* status / sort / tag filtering

! Quick start

# Tag any tiddler with `subscriptions` plus 1+ category tag.
# Open the [[Subscriptions]] view tiddler. (It ships as a shadow tiddler, so it won't appear in the sidebar's Recent/All tabs by default — type `Subscriptions` in the top search box, or visit `#Subscriptions` directly, or browse the sidebar's ''More → Shadows'' tab.)
# Click ''+ New subscription'' to add one.

! Configuration

* Display currency, tag-name, and renewal-soon threshold: see [[$:/plugins/realaaa/subscription-tracker/config/settings]]
* Currency rates: see [[$:/plugins/realaaa/subscription-tracker/config/rates]]

! License

MIT.
"},"$:/plugins/realaaa/subscription-tracker/styles":{"title":"$:/plugins/realaaa/subscription-tracker/styles","tags":"$:/tags/Stylesheet","text":"/* === Subscription Tracker stylesheet === */

/* Table */
.sub-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.95em;
    margin-top: 1em;
    table-layout: auto;
}
/* Guard against TW wikitext inserting stray <p> inside table sections,
   which the browser would otherwise foster-parent out and break column
   alignment between thead and tbody. display:contents makes the <p>
   transparent to layout while keeping its children in place. */
.sub-table p { display: contents; margin: 0; padding: 0; }
.sub-table th,
.sub-table td {
    padding: 8px 12px;
    border-bottom: 1px solid <<colour table-border>>;
    text-align: left;
    vertical-align: middle;
}
.sub-table th {
    background: <<colour table-header-background>>;
    font-weight: 600;
}
.sub-table td.num {
    text-align: right;
    font-variant-numeric: tabular-nums;
    white-space: nowrap;
}
/* Keep the Name column reasonable but allow long names to wrap rather than
   stretch the column at the cost of every other column. */
.sub-table th:first-child,
.sub-table td:first-child {
    max-width: 18em;
    word-break: break-word;
}
.sub-table tr:hover {
    background: <<colour table-footer-background>>;
}

/* Pills (status + tags) */
.sub-pill {
    display: inline-block;
    padding: 2px 10px;
    border-radius: 10px;
    font-size: 0.85em;
    margin-right: 4px;
    color: #fff;
}
.sub-status-active   { background: #c2410c; }
.sub-status-canceled { background: #15803d; }
.sub-status-trial    { background: #7e22ce; }
.sub-status-paused   { background: #525252; }
.sub-tag             { background: #b45309; }

/* Renewal-date highlight */
.sub-renewal-soon { color: #dc2626; font-weight: 600; }
.sub-renewal-ok   { color: inherit; }

/* Strict-error glyph */
.sub-error {
    color: #dc2626;
    font-weight: 600;
}

/* Filter bar */
.sub-filter-bar {
    display: flex;
    gap: 12px;
    align-items: center;
    margin: 1em 0;
    flex-wrap: wrap;
}
.sub-filter-bar select {
    padding: 4px 8px;
}

/* Totals bar */
.sub-totals {
    font-size: 1.1em;
    margin: 0.5em 0;
}
.sub-totals strong { font-weight: 600; }

/* Exclusion banner */
.sub-banner {
    padding: 8px 12px;
    background: <<colour message-background>>;
    border-left: 3px solid <<colour message-border>>;
    margin: 0.5em 0;
    font-size: 0.9em;
}
.sub-banner-error {
    background: #fee2e2;
    border-left-color: #dc2626;
}

/* Empty state */
.sub-empty {
    padding: 2em;
    text-align: center;
    color: <<colour muted-foreground>>;
    font-style: italic;
}
